import React, { useState } from 'react';
import styles from '../../styles/admin/AdminLogin.module.css';

const AdminLogin = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = () => {
    setError('');
    if (!email || !password) {
      setError('Please enter your email and password.');
      return;
    }
    setLoading(true);
    // Mock login — replace with Firebase Auth later
    setTimeout(() => {
      if (email === 'admin@mizuya.ph' && password === 'mizuya2026') {
        onLogin({ email });
      } else {
        setError('Invalid credentials. Try admin@mizuya.ph / mizuya2026');
        setLoading(false);
      }
    }, 800);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSubmit();
  };

  return (
    <div className={styles.page}>
      <div className={styles.card}>
        <div className={styles.cardTop}>
          <div className={styles.kanji}>管理</div>
          <h1 className={styles.title}>Admin Portal</h1>
          <p className={styles.subtitle}>Mizuya Exclusive Resort</p>
        </div>

        <div className={styles.form}>
          <div className={styles.field}>
            <label className={styles.label}>Email</label>
            <input
              className={styles.input}
              type="email"
              placeholder="admin@mizuya.ph"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onKeyDown={handleKeyDown}
              autoFocus
            />
          </div>

          <div className={styles.field}>
            <label className={styles.label}>Password</label>
            <input
              className={styles.input}
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              onKeyDown={handleKeyDown}
            />
          </div>

          {error && <p className={styles.error}>⚠ {error}</p>}

          <button
            className={styles.btn}
            onClick={handleSubmit}
            disabled={loading}
            type="button"
          >
            {loading ? (
              <span className={styles.spinner} />
            ) : (
              <>Sign In <span>→</span></>
            )}
          </button>
        </div>

        <p className={styles.hint}>
          Demo: <code>admin@mizuya.ph</code> / <code>mizuya2026</code>
        </p>
      </div>
    </div>
  );
};

export default AdminLogin;
